const SEVERITY_COLORS = { CRITICAL: "#ef4444", HIGH: "#f97316", MEDIUM: "#eab308", LOW: "#22c55e", INFO: "#3b82f6" };
const CATEGORY_COLORS = { "AI/LLM Threat": "#8b5cf6", "Supply Chain": "#ec4899", "Cloud Security": "#06b6d4", "General Cyber": "#f59e0b", "Research": "#10b981" };
const FRAMEWORK_TABS = ["Overview", "NIST AI RMF", "NIST 800-53", "ISO 27001/27002", "ITSG-33", "Huang et al."];

const SeverityBadge = ({ severity }) => (
  <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-bold" style={{ backgroundColor: SEVERITY_COLORS[severity] + "22", color: SEVERITY_COLORS[severity], border: `1px solid ${SEVERITY_COLORS[severity]}44` }}>
    {severity === "CRITICAL" && <AlertTriangle className="w-3 h-3 mr-1" />}
    {severity === "HIGH" && <AlertCircle className="w-3 h-3 mr-1" />}
    {severity === "INFO" && <Info className="w-3 h-3 mr-1" />}
    {severity}
  </span>
);

const StatCard = ({ icon: Icon, label, value, color, subtext }) => (
  <div className="bg-gray-800 border border-gray-700 rounded-lg p-4 flex items-center gap-3">
    <div className="p-2 rounded-lg" style={{ backgroundColor: color + "22" }}>
      <Icon className="w-5 h-5" style={{ color }} />
    </div>
    <div>
      <div className="text-2xl font-bold text-white">{value}</div>
      <div className="text-xs text-gray-400">{label}</div>
      {subtext && <div className="text-xs mt-0.5" style={{ color }}>{subtext}</div>}
    </div>
  </div>
);

const ItemRow = ({ item, isExpanded, onToggle }) => (
  <div className="border border-gray-700 rounded-lg mb-2 overflow-hidden transition-all duration-200" style={{ borderLeftColor: SEVERITY_COLORS[item.severity], borderLeftWidth: 4 }}>
    <div className="flex items-center gap-3 p-3 cursor-pointer hover:bg-gray-750" onClick={onToggle} style={{ backgroundColor: isExpanded ? "#1e293b" : "transparent" }}>
      {isExpanded ? <ChevronDown className="w-4 h-4 text-gray-400 flex-shrink-0" /> : <ChevronRight className="w-4 h-4 text-gray-400 flex-shrink-0" />}
      <SeverityBadge severity={item.severity} />
      <span className="text-xs px-2 py-0.5 rounded-full font-medium" style={{ backgroundColor: CATEGORY_COLORS[item.category] + "22", color: CATEGORY_COLORS[item.category] }}>{item.category}</span>
      <span className="text-sm font-medium text-gray-200 flex-1">{item.title}</span>
      {item.threatActor !== "N/A" && <span className="text-xs text-red-400 bg-red-400/10 px-2 py-0.5 rounded">{item.threatActor}</span>}
    </div>
    {isExpanded && (
      <div className="px-4 pb-4 bg-gray-800/50">
        <p className="text-sm text-gray-300 mb-3 leading-relaxed">{item.description}</p>
        <div className="grid grid-cols-2 gap-x-6 gap-y-2 text-xs">
          <div><span className="text-gray-500">Component:</span> <span className="text-gray-300">{item.affectedComponent}</span></div>
          <div><span className="text-gray-500">Supply Chain Stage:</span> <span className="text-gray-300">{item.supplyChainStage}</span></div>
          <div><span className="text-gray-500">Risk Type:</span> <span className="text-gray-300">{item.riskType}</span></div>
          <div><span className="text-gray-500">Response:</span> <span className="text-cyan-400 font-medium">{item.responseAction}</span></div>
        </div>
        <div className="mt-3 pt-3 border-t border-gray-700 grid grid-cols-2 gap-x-6 gap-y-2 text-xs">
          <div><span className="text-purple-400">NIST AI RMF:</span> <span className="text-gray-300">{item.nistAiRmf}</span></div>
          <div><span className="text-blue-400">NIST 800-53:</span> <span className="text-gray-300">{item.nist80053}</span></div>
          <div><span className="text-green-400">ISO 27001:</span> <span className="text-gray-300">{item.iso27001}</span></div>
          <div><span className="text-orange-400">ITSG-33:</span> <span className="text-gray-300">{item.itsg33}</span></div>
        </div>
        {item.huangRisk !== "N/A" && (
          <div className="mt-3 pt-3 border-t border-gray-700">
            <div className="text-xs text-pink-400 font-medium mb-1">Huang et al. Supply Chain Mapping</div>
            <div className="grid grid-cols-2 gap-x-6 gap-y-1 text-xs">
              <div><span className="text-gray-500">Stakeholder:</span> <span className="text-gray-300">{item.huangStakeholder}</span></div>
              <div><span className="text-gray-500">Risk:</span> <span className="text-gray-300">{item.huangRisk}</span></div>
              <div><span className="text-gray-500">Component:</span> <span className="text-gray-300">{item.huangComponent}</span></div>
              <div><span className="text-gray-500">Mitigation:</span> <span className="text-gray-300">{item.huangMitigation}</span></div>
            </div>
          </div>
        )}
      </div>
    )}
  </div>
);

const CustomTooltip = ({ active, payload, label }) => {
  if (!active || !payload) return null;
  return (
    <div className="bg-gray-800 border border-gray-600 rounded-lg p-3 shadow-xl">
      <p className="text-sm font-medium text-white mb-1">{label}</p>
      {payload.map((p, i) => (
        <p key={i} className="text-xs" style={{ color: p.color }}>{p.name}: {p.value}</p>
      ))}
    </div>
  );
};

export default function CyberDashboard() {
  const [activeFramework, setActiveFramework] = useState("Overview");
  const [severityFilter, setSeverityFilter] = useState("ALL");
  const [categoryFilter, setCategoryFilter] = useState("ALL");
  const [searchQuery, setSearchQuery] = useState("");
  const [expandedItems, setExpandedItems] = useState({});
  const [sortBy, setSortBy] = useState("severity");

  const items = TRACKER_DATA.items;

  const filteredItems = useMemo(() => {
    let result = items.filter(item => {
      if (severityFilter !== "ALL" && item.severity !== severityFilter) return false;
      if (categoryFilter !== "ALL" && item.category !== categoryFilter) return false;
      if (searchQuery) {
        const q = searchQuery.toLowerCase();
        return item.title.toLowerCase().includes(q) || item.description.toLowerCase().includes(q) || item.threatActor.toLowerCase().includes(q) || item.nist80053.toLowerCase().includes(q) || item.iso27001.toLowerCase().includes(q);
      }
      return true;
    });
    const sevOrder = { CRITICAL: 0, HIGH: 1, MEDIUM: 2, LOW: 3, INFO: 4 };
    if (sortBy === "severity") result.sort((a, b) => sevOrder[a.severity] - sevOrder[b.severity]);
    else if (sortBy === "category") result.sort((a, b) => a.category.localeCompare(b.category));
    return result;
  }, [items, severityFilter, categoryFilter, searchQuery, sortBy]);

  const stats = useMemo(() => {
    const bySev = {}, byCat = {}, byRmf = {}, byAction = {};
    items.forEach(i => {
      bySev[i.severity] = (bySev[i.severity] || 0) + 1;
      byCat[i.category] = (byCat[i.category] || 0) + 1;
      byRmf[i.nistAiRmf] = (byRmf[i.nistAiRmf] || 0) + 1;
      byAction[i.responseAction] = (byAction[i.responseAction] || 0) + 1;
    });
    return { bySev, byCat, byRmf, byAction };
  }, [items]);

  const severityPieData = Object.entries(stats.bySev).map(([name, value]) => ({ name, value }));
  const categoryPieData = Object.entries(stats.byCat).map(([name, value]) => ({ name, value }));

  const rmfRadarData = [
    { function: "Govern", count: stats.byRmf["Govern"] || 0, fullMark: 8 },
    { function: "Map", count: stats.byRmf["Map"] || 0, fullMark: 8 },
    { function: "Measure", count: stats.byRmf["Measure"] || 0, fullMark: 8 },
    { function: "Manage", count: stats.byRmf["Manage"] || 0, fullMark: 8 }
  ];

  const controlFamilyData = useMemo(() => {
    const families = {};
    items.forEach(i => {
      i.nist80053.split(",").map(c => c.trim().split("-")[0]).forEach(f => {
        if (f && f !== "N/A") families[f] = (families[f] || 0) + 1;
      });
    });
    return Object.entries(families).map(([name, count]) => ({ name, count })).sort((a, b) => b.count - a.count);
  }, [items]);

  const huangTreeData = useMemo(() => {
    const groups = {};
    items.filter(i => i.huangComponent !== "N/A").forEach(i => {
      const key = i.huangComponent;
      if (!groups[key]) groups[key] = { name: key, size: 0, items: [] };
      groups[key].size += 1;
      groups[key].items.push(i.title);
    });
    return Object.values(groups);
  }, [items]);

  const toggleExpand = (id) => setExpandedItems(prev => ({ ...prev, [id]: !prev[id] }));

  const renderOverview = () => (
    <div className="space-y-6">
      <div className="grid grid-cols-5 gap-4">
        <StatCard icon={Shield} label="Total Threats" value={items.length} color="#3b82f6" subtext="Today" />
        <StatCard icon={AlertTriangle} label="Critical" value={stats.bySev.CRITICAL || 0} color="#ef4444" subtext="Immediate action" />
        <StatCard icon={AlertCircle} label="High" value={stats.bySev.HIGH || 0} color="#f97316" subtext="Review today" />
        <StatCard icon={Target} label="AI/LLM Threats" value={stats.byCat["AI/LLM Threat"] || 0} color="#8b5cf6" subtext="Priority domain" />
        <StatCard icon={Activity} label="Active Actors" value={items.filter(i => !["N/A","Unknown","UNC/Unknown"].includes(i.threatActor)).length} color="#ec4899" subtext="Named groups" />
      </div>

      <div className="grid grid-cols-3 gap-4">
        <div className="bg-gray-800 border border-gray-700 rounded-lg p-4">
          <h3 className="text-sm font-semibold text-gray-300 mb-3">Severity Distribution</h3>
          <ResponsiveContainer width="100%" height={200}>
            <PieChart>
              <Pie data={severityPieData} cx="50%" cy="50%" outerRadius={75} innerRadius={40} dataKey="value" label={({ name, value }) => `${name}: ${value}`} labelLine={false}>
                {severityPieData.map((entry) => <Cell key={entry.name} fill={SEVERITY_COLORS[entry.name]} />)}
              </Pie>
              <Tooltip content={<CustomTooltip />} />
            </PieChart>
          </ResponsiveContainer>
        </div>

        <div className="bg-gray-800 border border-gray-700 rounded-lg p-4">
          <h3 className="text-sm font-semibold text-gray-300 mb-3">Threats by Category</h3>
          <ResponsiveContainer width="100%" height={200}>
            <BarChart data={categoryPieData} layout="vertical" margin={{ left: 0 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#374151" />
              <XAxis type="number" tick={{ fill: "#9ca3af", fontSize: 11 }} />
              <YAxis dataKey="name" type="category" width={100} tick={{ fill: "#9ca3af", fontSize: 10 }} />
              <Tooltip content={<CustomTooltip />} />
              <Bar dataKey="value" radius={[0, 4, 4, 0]}>
                {categoryPieData.map((entry) => <Cell key={entry.name} fill={CATEGORY_COLORS[entry.name] || "#6b7280"} />)}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>

        <div className="bg-gray-800 border border-gray-700 rounded-lg p-4">
          <h3 className="text-sm font-semibold text-gray-300 mb-3">7-Day Severity Trend</h3>
          <ResponsiveContainer width="100%" height={200}>
            <LineChart data={TRACKER_DATA.trendData}>
              <CartesianGrid strokeDasharray="3 3" stroke="#374151" />
              <XAxis dataKey="date" tick={{ fill: "#9ca3af", fontSize: 11 }} />
              <YAxis tick={{ fill: "#9ca3af", fontSize: 11 }} />
              <Tooltip content={<CustomTooltip />} />
              <Line type="monotone" dataKey="critical" stroke="#ef4444" strokeWidth={2} dot={{ r: 3 }} />
              <Line type="monotone" dataKey="high" stroke="#f97316" strokeWidth={2} dot={{ r: 3 }} />
              <Line type="monotone" dataKey="medium" stroke="#eab308" strokeWidth={1.5} dot={{ r: 2 }} />
              <Legend wrapperStyle={{ fontSize: 11, color: "#9ca3af" }} />
            </LineChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="bg-gray-800 border border-gray-700 rounded-lg p-4">
        <h3 className="text-sm font-semibold text-gray-300 mb-3">Response Actions Summary</h3>
        <div className="flex gap-4">
          {Object.entries(stats.byAction).map(([action, count]) => {
            const colors = { Investigate: "#ef4444", Escalate: "#f97316", Monitor: "#3b82f6", "N/A": "#6b7280" };
            const icons = { Investigate: Search, Escalate: ArrowUpRight, Monitor: Eye, "N/A": Info };
            const Icon = icons[action] || Info;
            return (
              <div key={action} className="flex-1 bg-gray-750 rounded-lg p-3 border border-gray-600 text-center">
                <Icon className="w-5 h-5 mx-auto mb-1" style={{ color: colors[action] || "#6b7280" }} />
                <div className="text-lg font-bold text-white">{count}</div>
                <div className="text-xs text-gray-400">{action}</div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );

  const renderNistAiRmf = () => (
    <div className="space-y-6">
      <div className="bg-gray-800 border border-gray-700 rounded-lg p-4">
        <h3 className="text-sm font-semibold text-gray-300 mb-3">NIST AI RMF Function Coverage</h3>
        <div className="flex gap-6 items-center">
          <ResponsiveContainer width="40%" height={250}>
            <RadarChart data={rmfRadarData}>
              <PolarGrid stroke="#374151" />
              <PolarAngleAxis dataKey="function" tick={{ fill: "#9ca3af", fontSize: 12 }} />
              <PolarRadiusAxis tick={{ fill: "#6b7280", fontSize: 10 }} />
              <Radar name="Threats" dataKey="count" stroke="#8b5cf6" fill="#8b5cf6" fillOpacity={0.3} />
            </RadarChart>
          </ResponsiveContainer>
          <div className="flex-1 space-y-3">
            {rmfRadarData.map(d => (
              <div key={d.function} className="flex items-center gap-3">
                <div className="w-20 text-sm font-medium text-purple-400">{d.function}</div>
                <div className="flex-1 bg-gray-700 rounded-full h-3 overflow-hidden">
                  <div className="h-full rounded-full bg-purple-500 transition-all" style={{ width: `${(d.count / items.length) * 100}%` }} />
                </div>
                <span className="text-sm text-gray-300 w-8 text-right">{d.count}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
      <div className="bg-gray-800 border border-gray-700 rounded-lg p-4">
        <h3 className="text-sm font-semibold text-gray-300 mb-3">Items by AI RMF Function</h3>
        {["Govern","Map","Measure","Manage"].map(fn => {
          const fnItems = items.filter(i => i.nistAiRmf === fn);
          if (!fnItems.length) return null;
          return (
            <div key={fn} className="mb-4">
              <h4 className="text-xs font-bold text-purple-400 uppercase tracking-wider mb-2">{fn} ({fnItems.length})</h4>
              {fnItems.map(item => <ItemRow key={item.id} item={item} isExpanded={expandedItems[item.id]} onToggle={() => toggleExpand(item.id)} />)}
            </div>
          );
        })}
      </div>
    </div>
  );

  const renderNist80053 = () => (
    <div className="space-y-6">
      <div className="bg-gray-800 border border-gray-700 rounded-lg p-4">
        <h3 className="text-sm font-semibold text-gray-300 mb-3">NIST 800-53 Control Family Heatmap</h3>
        <ResponsiveContainer width="100%" height={220}>
          <BarChart data={controlFamilyData}>
            <CartesianGrid strokeDasharray="3 3" stroke="#374151" />
            <XAxis dataKey="name" tick={{ fill: "#9ca3af", fontSize: 11 }} />
            <YAxis tick={{ fill: "#9ca3af", fontSize: 11 }} />
            <Tooltip content={<CustomTooltip />} />
            <Bar dataKey="count" fill="#3b82f6" radius={[4, 4, 0, 0]}>
              {controlFamilyData.map((entry, i) => <Cell key={i} fill={entry.count >= 3 ? "#ef4444" : entry.count >= 2 ? "#f97316" : "#3b82f6"} />)}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>
      <div className="bg-gray-800 border border-gray-700 rounded-lg p-4">
        <h3 className="text-sm font-semibold text-gray-300 mb-3">Control Mapping Detail</h3>
        <div className="overflow-x-auto">
          <table className="w-full text-xs">
            <thead>
              <tr className="border-b border-gray-600">
                <th className="text-left py-2 px-3 text-gray-400 font-medium">Severity</th>
                <th className="text-left py-2 px-3 text-gray-400 font-medium">Threat</th>
                <th className="text-left py-2 px-3 text-gray-400 font-medium">Controls</th>
                <th className="text-left py-2 px-3 text-gray-400 font-medium">Category</th>
                <th className="text-left py-2 px-3 text-gray-400 font-medium">Response</th>
              </tr>
            </thead>
            <tbody>
              {filteredItems.filter(i => i.nist80053 !== "N/A").map(item => (
                <tr key={item.id} className="border-b border-gray-700/50 hover:bg-gray-750">
                  <td className="py-2 px-3"><SeverityBadge severity={item.severity} /></td>
                  <td className="py-2 px-3 text-gray-300">{item.title}</td>
                  <td className="py-2 px-3"><span className="text-blue-400 font-mono">{item.nist80053}</span></td>
                  <td className="py-2 px-3 text-gray-400">{item.category}</td>
                  <td className="py-2 px-3 text-cyan-400">{item.responseAction}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );

  const renderIso = () => (
    <div className="space-y-6">
      <div className="bg-gray-800 border border-gray-700 rounded-lg p-4">
        <h3 className="text-sm font-semibold text-gray-300 mb-3">ISO 27001/27002 Control Mapping</h3>
        <div className="overflow-x-auto">
          <table className="w-full text-xs">
            <thead>
              <tr className="border-b border-gray-600">
                <th className="text-left py-2 px-3 text-gray-400">Severity</th>
                <th className="text-left py-2 px-3 text-gray-400">Threat</th>
                <th className="text-left py-2 px-3 text-gray-400">ISO Control</th>
                <th className="text-left py-2 px-3 text-gray-400">NIST 800-53 Cross-Ref</th>
                <th className="text-left py-2 px-3 text-gray-400">ITSG-33 Cross-Ref</th>
                <th className="text-left py-2 px-3 text-gray-400">Risk Type</th>
              </tr>
            </thead>
            <tbody>
              {filteredItems.map(item => (
                <tr key={item.id} className="border-b border-gray-700/50 hover:bg-gray-750">
                  <td className="py-2 px-3"><SeverityBadge severity={item.severity} /></td>
                  <td className="py-2 px-3 text-gray-300">{item.title}</td>
                  <td className="py-2 px-3"><span className="text-green-400 font-mono">{item.iso27001}</span></td>
                  <td className="py-2 px-3"><span className="text-blue-400 font-mono">{item.nist80053}</span></td>
                  <td className="py-2 px-3"><span className="text-orange-400 font-mono">{item.itsg33}</span></td>
                  <td className="py-2 px-3 text-gray-400">{item.riskType}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );

  const renderItsg = () => (
    <div className="space-y-6">
      <div className="bg-gray-800 border border-gray-700 rounded-lg p-4">
        <h3 className="text-sm font-semibold text-gray-300 mb-3">ITSG-33 Control Mapping (Canadian Framework)</h3>
        <p className="text-xs text-gray-400 mb-4">Cross-referenced with NIST 800-53 and ISO 27001 for unified assessment. All items mapped at Profile Level PB-3 or higher.</p>
        <div className="overflow-x-auto">
          <table className="w-full text-xs">
            <thead>
              <tr className="border-b border-gray-600">
                <th className="text-left py-2 px-3 text-gray-400">Severity</th>
                <th className="text-left py-2 px-3 text-gray-400">Threat</th>
                <th className="text-left py-2 px-3 text-gray-400">ITSG-33</th>
                <th className="text-left py-2 px-3 text-gray-400">NIST Cross-Ref</th>
                <th className="text-left py-2 px-3 text-gray-400">ISO Cross-Ref</th>
                <th className="text-left py-2 px-3 text-gray-400">Supply Chain Stage</th>
              </tr>
            </thead>
            <tbody>
              {filteredItems.map(item => (
                <tr key={item.id} className="border-b border-gray-700/50 hover:bg-gray-750">
                  <td className="py-2 px-3"><SeverityBadge severity={item.severity} /></td>
                  <td className="py-2 px-3 text-gray-300">{item.title}</td>
                  <td className="py-2 px-3"><span className="text-orange-400 font-mono">{item.itsg33}</span></td>
                  <td className="py-2 px-3"><span className="text-blue-400 font-mono">{item.nist80053}</span></td>
                  <td className="py-2 px-3"><span className="text-green-400 font-mono">{item.iso27001}</span></td>
                  <td className="py-2 px-3 text-gray-400">{item.supplyChainStage}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );

  const renderHuang = () => (
    <div className="space-y-6">
      <div className="bg-gray-800 border border-pink-500/30 rounded-lg p-4">
        <div className="flex items-center gap-2 mb-2">
          <BookOpen className="w-4 h-4 text-pink-400" />
          <h3 className="text-sm font-semibold text-pink-300">LLM Supply Chain Risk Taxonomy — Huang et al. (2024)</h3>
        </div>
        <p className="text-xs text-gray-400 leading-relaxed">Mapping today's incidents to the taxonomy from "Lifting the Veil on the Large Language Model Supply Chain: Composition, Risks, and Mitigations." Think of this as a DNA test for each threat — identifying exactly where in the LLM supply chain it strikes and what defenses apply.</p>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div className="bg-gray-800 border border-gray-700 rounded-lg p-4">
          <h3 className="text-sm font-semibold text-gray-300 mb-3">Threats by Supply Chain Component</h3>
          <ResponsiveContainer width="100%" height={220}>
            <BarChart data={huangTreeData} layout="vertical">
              <CartesianGrid strokeDasharray="3 3" stroke="#374151" />
              <XAxis type="number" tick={{ fill: "#9ca3af", fontSize: 11 }} />
              <YAxis dataKey="name" type="category" width={140} tick={{ fill: "#9ca3af", fontSize: 10 }} />
              <Tooltip content={<CustomTooltip />} />
              <Bar dataKey="size" fill="#ec4899" radius={[0, 4, 4, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>

        <div className="bg-gray-800 border border-gray-700 rounded-lg p-4">
          <h3 className="text-sm font-semibold text-gray-300 mb-3">Stakeholder Risk Breakdown</h3>
          <ResponsiveContainer width="100%" height={220}>
            <PieChart>
              <Pie data={(() => {
                const groups = {};
                items.filter(i => i.huangStakeholder !== "N/A").forEach(i => { groups[i.huangStakeholder] = (groups[i.huangStakeholder] || 0) + 1; });
                return Object.entries(groups).map(([name, value]) => ({ name, value }));
              })()} cx="50%" cy="50%" outerRadius={80} innerRadius={35} dataKey="value" label={({ name, value }) => `${name.replace("Risky ", "")}: ${value}`}>
                {["#ec4899", "#8b5cf6", "#06b6d4", "#f59e0b"].map((c, i) => <Cell key={i} fill={c} />)}
              </Pie>
              <Tooltip content={<CustomTooltip />} />
            </PieChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="bg-gray-800 border border-gray-700 rounded-lg p-4">
        <h3 className="text-sm font-semibold text-gray-300 mb-3">Detailed Risk Mapping</h3>
        <div className="overflow-x-auto">
          <table className="w-full text-xs">
            <thead>
              <tr className="border-b border-gray-600">
                <th className="text-left py-2 px-3 text-gray-400">Severity</th>
                <th className="text-left py-2 px-3 text-gray-400">Threat</th>
                <th className="text-left py-2 px-3 text-gray-400">Stakeholder</th>
                <th className="text-left py-2 px-3 text-gray-400">Component</th>
                <th className="text-left py-2 px-3 text-gray-400">Risk Code</th>
                <th className="text-left py-2 px-3 text-gray-400">Mitigation</th>
              </tr>
            </thead>
            <tbody>
              {filteredItems.filter(i => i.huangRisk !== "N/A").map(item => (
                <tr key={item.id} className="border-b border-gray-700/50 hover:bg-gray-750">
                  <td className="py-2 px-3"><SeverityBadge severity={item.severity} /></td>
                  <td className="py-2 px-3 text-gray-300">{item.title}</td>
                  <td className="py-2 px-3 text-pink-400">{item.huangStakeholder}</td>
                  <td className="py-2 px-3 text-cyan-400">{item.huangComponent}</td>
                  <td className="py-2 px-3 text-yellow-400 font-mono">{item.huangRisk}</td>
                  <td className="py-2 px-3 text-gray-400">{item.huangMitigation}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );

  const frameworkRenderers = {
    "Overview": renderOverview,
    "NIST AI RMF": renderNistAiRmf,
    "NIST 800-53": renderNist80053,
    "ISO 27001/27002": renderIso,
    "ITSG-33": renderItsg,
    "Huang et al.": renderHuang
  };

  return (
    <div className="min-h-screen bg-gray-900 text-white">
      {/* Header */}
      <div className="bg-gradient-to-r from-gray-900 via-blue-900/30 to-gray-900 border-b border-gray-700 px-6 py-4">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <Shield className="w-8 h-8 text-cyan-400" />
            <div>
              <h1 className="text-xl font-bold bg-gradient-to-r from-cyan-400 to-blue-400 bg-clip-text" style={{ WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>SAI Cloud Secure</h1>
              <p className="text-xs text-gray-400">Cyber Intelligence Dashboard</p>
            </div>
          </div>
          <div className="text-right">
            <div className="flex items-center gap-2 text-sm text-gray-300">
              <Clock className="w-4 h-4" />
              <span>April 10, 2026</span>
            </div>
            <div className="text-xs text-gray-500 mt-0.5">Auto-refreshed daily at 07:00</div>
          </div>
        </div>
      </div>

      <div className="px-6 py-4">
        {/* Framework Tabs */}
        <div className="flex gap-1 mb-4 bg-gray-800 rounded-lg p-1 border border-gray-700">
          {FRAMEWORK_TABS.map(tab => (
            <button key={tab} onClick={() => setActiveFramework(tab)}
              className={`px-4 py-2 rounded-md text-xs font-medium transition-all ${activeFramework === tab ? "bg-cyan-500/20 text-cyan-400 border border-cyan-500/30" : "text-gray-400 hover:text-gray-200 hover:bg-gray-700 border border-transparent"}`}>
              {tab}
            </button>
          ))}
        </div>

        {/* Filters */}
        <div className="flex items-center gap-3 mb-4">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500" />
            <input type="text" placeholder="Search threats, controls, actors..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-gray-800 border border-gray-700 rounded-lg pl-10 pr-4 py-2 text-sm text-gray-200 placeholder-gray-500 focus:outline-none focus:border-cyan-500" />
          </div>
          <div className="flex gap-1">
            {["ALL", "CRITICAL", "HIGH", "MEDIUM", "LOW", "INFO"].map(sev => (
              <button key={sev} onClick={() => setSeverityFilter(sev)}
                className={`px-3 py-1.5 rounded text-xs font-medium transition-all ${severityFilter === sev ? "ring-1" : "opacity-60 hover:opacity-100"}`}
                style={sev === "ALL" ? { backgroundColor: severityFilter === sev ? "#374151" : "transparent", color: "#9ca3af" } : { backgroundColor: (SEVERITY_COLORS[sev] || "#6b7280") + (severityFilter === sev ? "33" : "11"), color: SEVERITY_COLORS[sev] || "#9ca3af" }}>
                {sev}
              </button>
            ))}
          </div>
          <select value={categoryFilter} onChange={(e) => setCategoryFilter(e.target.value)}
            className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-1.5 text-xs text-gray-300 focus:outline-none focus:border-cyan-500">
            <option value="ALL">All Categories</option>
            {Object.keys(CATEGORY_COLORS).map(cat => <option key={cat} value={cat}>{cat}</option>)}
          </select>
          <select value={sortBy} onChange={(e) => setSortBy(e.target.value)}
            className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-1.5 text-xs text-gray-300 focus:outline-none focus:border-cyan-500">
            <option value="severity">Sort: Severity</option>
            <option value="category">Sort: Category</option>
          </select>
          <div className="text-xs text-gray-500">{filteredItems.length} of {items.length} items</div>
        </div>

        {/* Main Content */}
        {frameworkRenderers[activeFramework]?.()}

        {/* Item List (shown below framework views except Overview) */}
        {activeFramework !== "Overview" ? null : (
          <div className="mt-6 bg-gray-800/50 border border-gray-700 rounded-lg p-4">
            <h3 className="text-sm font-semibold text-gray-300 mb-3 flex items-center gap-2">
              <Layers className="w-4 h-4 text-cyan-400" />
              All Threat Items ({filteredItems.length})
            </h3>
            {filteredItems.map(item => (
              <ItemRow key={item.id} item={item} isExpanded={expandedItems[item.id]} onToggle={() => toggleExpand(item.id)} />
            ))}
          </div>
        )}

        {/* Footer */}
        <div className="mt-8 pt-4 border-t border-gray-800 flex items-center justify-between text-xs text-gray-600">
          <span>SAI Cloud Secure Cyber Intelligence Platform</span>
          <span>Data sourced from Cyber_AI_Daily_Tracker.xlsx | Frameworks: NIST AI RMF, 800-53, ISO 27001, ITSG-33, Huang et al.</span>
          <span>Classification: INTERNAL</span>
        </div>
      </div>
    </div>
  );
}